package com.infy.inventrack.user.config; import com.infy.inventrack.common.enums.UserRole; import com.infy.inventrack.user.entity.AppUser; import com.infy.inventrack.user.repository.UserRepository; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import org.springframework.security.crypto.password.PasswordEncoder; @Configuration public class DataSeeder { @Bean CommandLineRunner seedUsers(UserRepository repo,PasswordEncoder enc){ return args->{ seed(repo,enc,"admin","Admin@123","admin@example.com",UserRole.ADMIN); seed(repo,enc,"customer","Customer@123","customer@example.com",UserRole.CUSTOMER); }; } private void seed(UserRepository repo,PasswordEncoder enc,String n,String p,String e,UserRole r){ if(!repo.existsByUserNameIgnoreCase(n)){ AppUser u=new AppUser(); u.setUserName(n); u.setPassword(enc.encode(p)); u.setEmail(e); u.setRole(r); repo.save(u); } } }
